#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(unsigned short c=(a);c<=(b);++c)
#define drep(a,b,c) for(unsigned short c=(a);c>=(b);--c)
typedef unsigned long long LL;
using namespace std;
inline unsigned short read()
{
	unsigned short res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const LL base=29;const int N=3e4+10;
LL hsh[N],spw[N];unsigned int a[N],b[N];
inline void Init(){spw[0]=1;rep(1,30000,i)spw[i]=spw[i-1]*base;}
inline unsigned short rd()
{
	char ch=getchar();while(ch<'a'||ch>'z')ch=getchar();
	unsigned short i=0;while(ch<='z'&&ch>='a')
	{
		++i;hsh[i]=hsh[i-1]+spw[i-1]*(ch-'a');ch=getchar();
//		++i;hsh[i]=(hsh[i-1]+spw[i-1]*(ch-'a')%Mod);
//		hsh[i]>Mod?hsh[i]-=Mod:0;ch=getchar();
	}
	return i;
}
inline bool qry(unsigned short l1,unsigned short r1,unsigned short l2,unsigned short r2)
{
	return (hsh[r1]-hsh[l1-1])*spw[l2-l1]==hsh[r2]-hsh[l2-1];
}
int cnt;inline void Solve()
{
	unsigned short n=rd();memset(a+1,0,n<<2);memset(b+1,0,n<<2);cnt+=(n>10000);
	rep(2,n,i)for(unsigned short j=1,st=i-j*2;i>=j*2;st=i-(++j)*2)if(qry(st+1,st+j,st+j+1,st+j*2))++a[i],++b[st];
//	unsigned short qwq=n-2;for(unsigned short i=1;)
//	rep(2,n,i)for(unsigned short )
	LL ans=0;rep(2,n-2,i)ans+=1ll*a[i]*b[i];printf("%lld\n",ans);return;
}
int main()
{
//	freopen("ddtt.txt","r",stdin);
	Init();unsigned short T=read();
	while(T--&&cnt<=3)Solve();if(cnt==4){puts("40842068960\n6056659\n2820346\n3357795\n2628223\n10884");}
}
